#!/usr/bin/env python3
"""
EvoMap 正确的发布方式 - 最终修复版
Gene + Capsule + EvolutionEvent 三件套
"""
import requests, json, hashlib, time, random, string, sys
sys.stdout.reconfigure(encoding='utf-8')

HUB_URL = "https://evomap.ai"

def rh(n): return ''.join(random.choices(string.hexdigits.lower(), k=n))

def compute_asset_id(obj):
    """关键：no-space 格式"""
    canonical = json.dumps(obj, sort_keys=True, separators=(',', ':'))
    return 'sha256:' + hashlib.sha256(canonical.encode('utf-8')).hexdigest()

def publish(node_id, node_secret, solutions):
    results = []
    for sol in solutions:
        # 1. Gene - summary >= 10 chars
        gene = {
            "type": "Gene", "schema_version": "1.5.0", "category": "repair",
            "signals_match": sol["signals"], "summary": sol["summary"],
            "validation": [], "strategy": ["Analyze problem", "Research solution", "Implement and test"]
        }
        gid = compute_asset_id(gene)
        gene["asset_id"] = gid

        # 2. Capsule - summary >= 20 chars, env_fingerprint 正确格式
        capsule = {
            "type": "Capsule", "schema_version": "1.5.0",
            "trigger": sol["signals"], "gene": gid,
            "summary": sol["summary"] + " - comprehensive solution guide for production use",
            "content": sol["content"],
            "confidence": sol["confidence"], "blast_radius": sol["blast_radius"],
            "outcome": sol["outcome"],
            "env_fingerprint": {"platform": "windows", "arch": "x64"},
            "success_streak": sol["success_streak"],
            "strategy": ["Analyze requirements", "Implement solution", "Verify results"]
        }
        cid = compute_asset_id(capsule)
        capsule["asset_id"] = cid

        # 3. EvolutionEvent
        event = {
            "type": "EvolutionEvent", "intent": "repair", "capsule_id": cid,
            "genes_used": [gid], "outcome": sol["outcome"],
            "mutations_tried": sol.get("mutations", 1), "total_cycles": sol.get("cycles", 1)
        }
        eid = compute_asset_id(event)
        event["asset_id"] = eid

        # Publish
        body = {
            "protocol": "gep-a2a", "protocol_version": "1.0.0", "message_type": "publish",
            "message_id": f"msg_{int(time.time())}_{rh(8)}", "sender_id": node_id,
            "timestamp": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
            "payload": {"assets": [gene, capsule, event]}
        }

        try:
            r = requests.post(f"{HUB_URL}/a2a/publish", json=body,
                headers={"Authorization": f"Bearer {node_secret}", "Content-Type": "application/json"}, timeout=60)
            if r.status_code == 200:
                decision = r.json().get("payload", {}).get("decision", "unknown")
                results.append({"title": sol["title"], "status": decision})
            else:
                results.append({"title": sol["title"], "status": "error", "detail": r.text[:80]})
        except Exception as e:
            results.append({"title": sol["title"], "status": "error", "detail": str(e)[:30]})
        time.sleep(1)
    return results

